import React from 'react';

const StatCard = ({ title, value, icon: Icon, color = 'primary', trend, trendValue, subtitle }) => {
  const colors = {
    primary: { bg: 'from-primary-400 to-primary-600', light: 'bg-primary-50', text: 'text-primary-600' },
    green: { bg: 'from-green-400 to-green-600', light: 'bg-green-50', text: 'text-green-600' },
    blue: { bg: 'from-blue-400 to-blue-600', light: 'bg-blue-50', text: 'text-blue-600' },
    purple: { bg: 'from-purple-400 to-purple-600', light: 'bg-purple-50', text: 'text-purple-600' },
    orange: { bg: 'from-orange-400 to-orange-600', light: 'bg-orange-50', text: 'text-orange-600' },
    red: { bg: 'from-red-400 to-red-600', light: 'bg-red-50', text: 'text-red-600' },
  };

  return (
    <div className="stat-card card-hover">
      <div className="flex items-start justify-between">
        <div className="flex-1">
          <p className="text-sm font-medium text-secondary-500 mb-1">{title}</p>
          <p className="text-3xl font-bold text-secondary-800">{value}</p>
          {subtitle && (
            <p className="text-xs text-secondary-400 mt-1">{subtitle}</p>
          )}
          {trend && (
            <div className={`flex items-center gap-1 mt-2 text-sm font-medium ${trend === 'up' ? 'text-green-600' : 'text-red-600'}`}>
              {trend === 'up' ? (
                <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 10l7-7m0 0l7 7m-7-7v18" />
                </svg>
              ) : (
                <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 14l-7 7m0 0l-7-7m7 7V3" />
                </svg>
              )}
              {trendValue}
            </div>
          )}
        </div>
        {Icon && (
          <div className={`w-14 h-14 bg-gradient-to-br ${colors[color].bg} rounded-xl flex items-center justify-center shadow-lg`}>
            <Icon className="w-7 h-7 text-white" />
          </div>
        )}
      </div>
    </div>
  );
};

export default StatCard;
